using System;
using System.Data.SqlClient;
using System.IO;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Newtonsoft.Json;

public static class AzureSQLQueryFunction
{
    [FunctionName("AzureSQLQueryFunction")]
    public static IActionResult Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        string sqlConnectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        string queryString = req.Query["query"];
        string parameters = req.Query["parameters"];

        if (string.IsNullOrEmpty(queryString) || string.IsNullOrEmpty(parameters))
        {
            return new BadRequestObjectResult("Query and parameters are required.");
        }

        try
        {
            using (SqlConnection conn = new SqlConnection(sqlConnectionString))
            {
                conn.Open();

                // Replace placeholders in the query with actual parameter values
                string safeQuery = ReplaceParameters(queryString, parameters);

                using (SqlCommand cmd = new SqlCommand(safeQuery, conn))
                {
                    using (SqlDataReader reader = cmd.ExecuteReader())
                    {
                        var results = new List<object>();
                        while (reader.Read())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row.Add(reader.GetName(i), reader[i]);
                            }
                            results.Add(row);
                        }

                        return new OkObjectResult(results);
                    }
                }
            }
        }
        catch (Exception ex)
        {
            log.LogError(ex, "Error executing SQL query.");
            return new InternalServerErrorResult();
        }
    }

    private static string ReplaceParameters(string queryString, string parameters)
    {
        var parameterArray = JsonConvert.DeserializeObject<Dictionary<string, object>>(parameters);
        foreach (var param in parameterArray)
        {
            queryString = queryString.Replace("{" + param.Key + "}", param.Value.ToString());
        }
        return queryString;
    }
